cat > /tmp/check_kindle.sh << 'SCRIPT'
#!/bin/bash

# Find all _kindle functions and check for violations
find /Users/bhyslop/projects/rbm_alpha_recipemuster/Tools/buk /Users/bhyslop/projects/rbm_alpha_recipemuster/Tools/rbk -name "*.sh" -type f | while read file; do
  awk '
  /^z[a-z_]*_kindle\(\)\s*\{/ {
    in_kindle = 1
    func_name = gensub(/^([a-z_]*_kindle)\(\)\s*\{/, "\\1", 1)
    start_line = NR
    next
  }

  in_kindle && /^}/ {
    in_kindle = 0
    # Check that last assignment before closing brace is KINDLED
    if (last_assign != "" && last_assign !~ /_KINDLED=1/) {
      print FILENAME ":" NR ": VIOLATION: KINDLED not last statement in " func_name " (last was: " last_assign ")"
    }
    last_assign = ""
    next
  }

  in_kindle {
    # Check for Z_PREFIX assignments without readonly
    if (/^\s*[A-Z][A-Z_]*=/ && !/^\s*readonly\s+/) {
      var_name = gensub(/^\s*([A-Z_]*=).*/, "\\1", 1, $0)
      print FILENAME ":" NR ": VIOLATION: Missing readonly in kindle for " var_name
    }
    # Track last assignment
    if (/^\s*(readonly\s+)?Z[A-Z_]*=/) {
      last_assign = $0
    }
  }
  ' "$file"
done
SCRIPT
bash /tmp/check_kindle.sh
